#include <bits/stdc++.h>
using namespace std;
int main(){long long n,k;scanf("%lld %lld",&n,&k);map<long long,long long>c;for(int i=0;i<n;i++){long long x;scanf("%lld",&x);c[x]++;}string out;for(auto&kv:c)if(kv.second>=k){out+=to_string(kv.first);out+=' ';}if(out.empty())puts("-1");else{out.back()='\n';fputs(out.c_str(),stdout);}}
